#!/usr/bin/env python3
"""Shared Devin API HTTP client."""
import os
import sys
import requests


class DevinAPIClient:
    """Client for Devin API interactions."""

    def __init__(self):
        self.api_token = os.environ.get("DEVIN_API")
        if not self.api_token:
            print(
                '{"error": "DEVIN_API environment variable not set"}', file=sys.stderr
            )
            sys.exit(1)

        self.base_url = "https://api.devin.ai/v1"
        self.headers = {
            "Authorization": f"Bearer {self.api_token}",
            "Content-Type": "application/json",
        }

    def spawn_session(self, repo, task, context=None):
        """Spawn a new Devin session."""
        payload = {"repo": repo, "task": task}
        if context:
            payload["context"] = context

        try:
            response = requests.post(
                f"{self.base_url}/sessions",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {"error": str(e)}

    def get_session_status(self, session_id):
        """Get status of a Devin session."""
        try:
            response = requests.get(
                f"{self.base_url}/sessions/{session_id}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {"error": str(e)}

#!/usr/bin/env python3
"""Manage Devin knowledge notes (breadcrumbs) via the Devin API."""
import argparse
import json
import os
import sys
import requests


class DevinKnowledgeManager:
    """Client for managing Devin knowledge notes."""

    def __init__(self):
        self.api_token = os.environ.get("DEVIN_API")
        if not self.api_token:
            print(
                '{"error": "DEVIN_API environment variable not set"}', file=sys.stderr
            )
            sys.exit(1)

        self.base_url = "https://api.devin.ai/v1"
        self.headers = {
            "Authorization": f"Bearer {self.api_token}",
            "Content-Type": "application/json",
        }

    def get_knowledge(self, knowledge_id):
        """Retrieve a knowledge note by ID.

        Args:
            knowledge_id: The ID of the knowledge note.

        Returns:
            dict with the knowledge note content or error.
        """
        try:
            response = requests.get(
                f"{self.base_url}/knowledge/{knowledge_id}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def update_knowledge(self, knowledge_id, content):
        """Update a knowledge note by ID.

        Args:
            knowledge_id: The ID of the knowledge note.
            content: New content for the note.

        Returns:
            dict with success status or error.
        """
        payload = {"content": content}

        try:
            response = requests.patch(
                f"{self.base_url}/knowledge/{knowledge_id}",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return {"success": True, "knowledge_id": knowledge_id}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def create_knowledge(self, title, content, trigger_type="keyword", trigger=None):
        """Create a new knowledge note.

        Args:
            title: Title of the knowledge note.
            content: Content of the note.
            trigger_type: How the note is triggered ("keyword", "always", etc.).
            trigger: Trigger value (e.g., keyword string).

        Returns:
            dict with the created note or error.
        """
        payload = {
            "title": title,
            "content": content,
            "trigger_type": trigger_type,
        }
        if trigger:
            payload["trigger"] = trigger

        try:
            response = requests.post(
                f"{self.base_url}/knowledge",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_knowledge(self):
        """List all knowledge notes.

        Returns:
            dict with the list of notes or error.
        """
        try:
            response = requests.get(
                f"{self.base_url}/knowledge",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def update_breadcrumbs(self, target_ids, content):
        """Update multiple knowledge notes (breadcrumbs) with the same content.

        Args:
            target_ids: List of knowledge note IDs to update.
            content: Content to set on each note.

        Returns:
            dict with results for each target.
        """
        results = {}
        for kid in target_ids:
            results[kid] = self.update_knowledge(kid, content)
        return {
            "breadcrumb_results": results,
            "total": len(target_ids),
            "success_count": sum(
                1 for r in results.values() if r.get("success")
            ),
        }


def main():
    parser = argparse.ArgumentParser(description="Devin Knowledge Management CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    # list command
    subparsers.add_parser("list", help="List all knowledge notes")

    # get command
    get_parser = subparsers.add_parser("get", help="Get a knowledge note by ID")
    get_parser.add_argument("--id", required=True, help="Knowledge note ID")

    # create command
    create_parser = subparsers.add_parser("create", help="Create a knowledge note")
    create_parser.add_argument("--title", required=True, help="Note title")
    create_parser.add_argument("--content", required=True, help="Note content")
    create_parser.add_argument(
        "--trigger-type",
        default="keyword",
        help="Trigger type (default: keyword)",
    )
    create_parser.add_argument("--trigger", default=None, help="Trigger value")

    # update command
    update_parser = subparsers.add_parser("update", help="Update a knowledge note")
    update_parser.add_argument("--id", required=True, help="Knowledge note ID")
    update_parser.add_argument("--content", required=True, help="New content")

    # breadcrumbs command
    bc_parser = subparsers.add_parser(
        "breadcrumbs", help="Update multiple knowledge notes with the same content"
    )
    bc_parser.add_argument(
        "--targets",
        required=True,
        help="Comma-separated list of knowledge note IDs",
    )
    bc_parser.add_argument(
        "--content", required=True, help="Content to set on each note"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    manager = DevinKnowledgeManager()

    if args.command == "list":
        result = manager.list_knowledge()
    elif args.command == "get":
        result = manager.get_knowledge(args.id)
    elif args.command == "create":
        result = manager.create_knowledge(
            args.title, args.content, args.trigger_type, args.trigger
        )
    elif args.command == "update":
        result = manager.update_knowledge(args.id, args.content)
    elif args.command == "breadcrumbs":
        target_ids = [t.strip() for t in args.targets.split(",")]
        result = manager.update_breadcrumbs(target_ids, args.content)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Discord CLI for sending messages and embeds via webhooks."""
import argparse
import json
import os
import sys
import requests


class DiscordClient:
    """Client for Discord Webhook interactions."""

    def __init__(self):
        self.webhook_url = os.environ.get("DISCORD_WEBHOOK_URL", "")
        if not self.webhook_url:
            print(
                '{"error": "DISCORD_WEBHOOK_URL environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)

    def send(self, text):
        """Send a text message via Discord webhook."""
        try:
            response = requests.post(
                self.webhook_url,
                json={"content": text},
                headers={"Content-Type": "application/json"},
                timeout=30,
            )
            response.raise_for_status()
            if response.status_code == 204:
                return {"success": True, "message": "Message sent"}
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def send_embed(self, title, description, color=None):
        """Send an embed message via Discord webhook."""
        embed = {"title": title, "description": description}
        if color is not None:
            embed["color"] = color

        try:
            response = requests.post(
                self.webhook_url,
                json={"embeds": [embed]},
                headers={"Content-Type": "application/json"},
                timeout=30,
            )
            response.raise_for_status()
            if response.status_code == 204:
                return {"success": True, "message": "Embed sent"}
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Discord CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    send_parser = subparsers.add_parser("send", help="Send a text message")
    send_parser.add_argument("--text", required=True, help="Message text")

    embed_parser = subparsers.add_parser("send-embed", help="Send an embed message")
    embed_parser.add_argument("--title", required=True, help="Embed title")
    embed_parser.add_argument(
        "--description", required=True, help="Embed description"
    )
    embed_parser.add_argument(
        "--color", type=int, default=None, help="Embed color as integer (e.g., 5814783)"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = DiscordClient()

    if args.command == "send":
        result = client.send(args.text)
    elif args.command == "send-embed":
        result = client.send_embed(args.title, args.description, args.color)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Docker Hub CLI for listing repositories, tags, and searching images."""
import argparse
import json
import os
import sys
import requests


class DockerHubClient:
    """Client for Docker Hub API interactions."""

    def __init__(self):
        self.username = os.environ.get("DOCKERHUB_USERNAME", "")
        if not self.username:
            print(
                '{"error": "DOCKERHUB_USERNAME environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.token_env = os.environ.get("DOCKERHUB_TOKEN", "")
        if not self.token_env:
            print(
                '{"error": "DOCKERHUB_TOKEN environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = "https://hub.docker.com/v2"
        self.jwt_token = self._login()
        self.headers = {
            "Authorization": f"JWT {self.jwt_token}",
            "Content-Type": "application/json",
        }

    def _login(self):
        """Authenticate and get JWT token."""
        try:
            response = requests.post(
                f"{self.base_url}/users/login/",
                json={
                    "username": self.username,
                    "password": self.token_env,
                },
                timeout=30,
            )
            response.raise_for_status()
            return response.json().get("token", "")
        except requests.exceptions.RequestException as e:
            print(
                json.dumps({
                    "error": f"Docker Hub login failed: {str(e)}",
                    "status_code": getattr(e.response, "status_code", None),
                }),
                file=sys.stderr,
            )
            sys.exit(1)

    def list_repos(self, namespace=None):
        """List repositories for a namespace."""
        ns = namespace or self.username
        try:
            response = requests.get(
                f"{self.base_url}/repositories/{ns}/",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_tags(self, repo):
        """List tags for a repository."""
        try:
            response = requests.get(
                f"{self.base_url}/repositories/{repo}/tags/",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_repo(self, repo):
        """Get repository details."""
        try:
            response = requests.get(
                f"{self.base_url}/repositories/{repo}/",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def search(self, query):
        """Search Docker Hub for images."""
        try:
            response = requests.get(
                f"{self.base_url}/search/repositories/",
                headers=self.headers,
                params={"query": query},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Docker Hub CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    repos_parser = subparsers.add_parser("list-repos", help="List repositories")
    repos_parser.add_argument(
        "--namespace", help="Namespace (defaults to your username)"
    )

    tags_parser = subparsers.add_parser("list-tags", help="List tags for a repository")
    tags_parser.add_argument(
        "--repo", required=True, help="Repository (e.g., library/nginx)"
    )

    get_parser = subparsers.add_parser("get-repo", help="Get repository details")
    get_parser.add_argument(
        "--repo", required=True, help="Repository (e.g., library/nginx)"
    )

    search_parser = subparsers.add_parser("search", help="Search for images")
    search_parser.add_argument("--query", required=True, help="Search query")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = DockerHubClient()

    if args.command == "list-repos":
        result = client.list_repos(
            namespace=getattr(args, "namespace", None),
        )
    elif args.command == "list-tags":
        result = client.list_tags(args.repo)
    elif args.command == "get-repo":
        result = client.get_repo(args.repo)
    elif args.command == "search":
        result = client.search(args.query)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

