#!/usr/bin/env python3
"""Elasticsearch CLI for searching, indexing, and managing indices and documents."""
import argparse
import json
import os
import sys

try:
    from elasticsearch import Elasticsearch, ElasticsearchException
except ImportError:
    print(
        '{"error": "elasticsearch package required. Install with: pip install elasticsearch>=8.10.0"}',
        file=sys.stderr,
    )
    sys.exit(1)


class ElasticsearchClient:
    """Client for Elasticsearch interactions."""

    def __init__(self):
        self.url = os.environ.get("ELASTICSEARCH_URL", "")
        if not self.url:
            print(
                '{"error": "ELASTICSEARCH_URL environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        api_key = os.environ.get("ELASTICSEARCH_API_KEY", "")
        kwargs = {"hosts": [self.url], "request_timeout": 30}
        if api_key:
            kwargs["api_key"] = api_key
        try:
            self.client = Elasticsearch(**kwargs)
        except Exception as e:
            print(
                json.dumps({"error": f"Failed to connect to Elasticsearch: {str(e)}"}),
                file=sys.stderr,
            )
            sys.exit(1)

    def search(self, index, query_json):
        """Search an index with a query."""
        try:
            query = json.loads(query_json)
        except json.JSONDecodeError as e:
            return {"error": f"Invalid JSON in --query-json: {str(e)}"}

        try:
            result = self.client.search(index=index, body=query)
            return {
                "hits": result["hits"]["total"],
                "documents": [hit["_source"] for hit in result["hits"]["hits"]],
                "max_score": result["hits"]["max_score"],
            }
        except ElasticsearchException as e:
            return {"error": str(e)}

    def list_indices(self):
        """List all indices."""
        try:
            indices = self.client.cat.indices(format="json")
            return {"indices": indices}
        except ElasticsearchException as e:
            return {"error": str(e)}

    def get_document(self, index, doc_id):
        """Get a document by ID."""
        try:
            result = self.client.get(index=index, id=doc_id)
            return {
                "index": result["_index"],
                "id": result["_id"],
                "source": result["_source"],
                "version": result["_version"],
            }
        except ElasticsearchException as e:
            return {"error": str(e)}

    def index_document(self, index, doc_id, body_json):
        """Index (create/update) a document."""
        try:
            body = json.loads(body_json)
        except json.JSONDecodeError as e:
            return {"error": f"Invalid JSON in --body-json: {str(e)}"}

        try:
            result = self.client.index(index=index, id=doc_id, body=body)
            return {
                "result": result["result"],
                "index": result["_index"],
                "id": result["_id"],
                "version": result["_version"],
            }
        except ElasticsearchException as e:
            return {"error": str(e)}


def main():
    parser = argparse.ArgumentParser(description="Elasticsearch CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    search_parser = subparsers.add_parser("search", help="Search an index")
    search_parser.add_argument("--index", required=True, help="Index name")
    search_parser.add_argument(
        "--query-json", required=True, help="Search query as JSON string"
    )

    subparsers.add_parser("list-indices", help="List all indices")

    get_parser = subparsers.add_parser("get-document", help="Get a document by ID")
    get_parser.add_argument("--index", required=True, help="Index name")
    get_parser.add_argument("--id", required=True, help="Document ID")

    index_parser = subparsers.add_parser(
        "index-document", help="Index a document"
    )
    index_parser.add_argument("--index", required=True, help="Index name")
    index_parser.add_argument("--id", required=True, help="Document ID")
    index_parser.add_argument(
        "--body-json", required=True, help="Document body as JSON string"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = ElasticsearchClient()

    if args.command == "search":
        result = client.search(args.index, args.query_json)
    elif args.command == "list-indices":
        result = client.list_indices()
    elif args.command == "get-document":
        result = client.get_document(args.index, args.id)
    elif args.command == "index-document":
        result = client.index_document(args.index, args.id, args.body_json)

    print(json.dumps(result, indent=2, default=str))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Figma CLI for retrieving files, comments, versions, and exporting images."""
import argparse
import json
import os
import sys
import requests


class FigmaClient:
    """Client for Figma API interactions."""

    def __init__(self):
        self.access_token = os.environ.get("FIGMA_ACCESS_TOKEN", "")
        if not self.access_token:
            print(
                '{"error": "FIGMA_ACCESS_TOKEN environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = "https://api.figma.com/v1"
        self.headers = {
            "X-Figma-Token": self.access_token,
            "Content-Type": "application/json",
        }

    def get_file(self, file_key):
        """Get a Figma file by key."""
        try:
            response = requests.get(
                f"{self.base_url}/files/{file_key}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_comments(self, file_key):
        """List comments on a Figma file."""
        try:
            response = requests.get(
                f"{self.base_url}/files/{file_key}/comments",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def export_images(self, file_key, node_ids, fmt="png"):
        """Export images from a Figma file."""
        try:
            response = requests.get(
                f"{self.base_url}/images/{file_key}",
                headers=self.headers,
                params={"ids": node_ids, "format": fmt},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_file_versions(self, file_key):
        """Get version history for a Figma file."""
        try:
            response = requests.get(
                f"{self.base_url}/files/{file_key}/versions",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Figma CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    get_file_parser = subparsers.add_parser("get-file", help="Get a Figma file")
    get_file_parser.add_argument("--file-key", required=True, help="Figma file key")

    comments_parser = subparsers.add_parser("list-comments", help="List file comments")
    comments_parser.add_argument("--file-key", required=True, help="Figma file key")

    export_parser = subparsers.add_parser("export-images", help="Export images")
    export_parser.add_argument("--file-key", required=True, help="Figma file key")
    export_parser.add_argument(
        "--node-ids", required=True, help="Comma-separated node IDs"
    )
    export_parser.add_argument(
        "--format", default="png", help="Export format (png, jpg, svg, pdf)"
    )

    versions_parser = subparsers.add_parser(
        "get-file-versions", help="Get file version history"
    )
    versions_parser.add_argument("--file-key", required=True, help="Figma file key")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = FigmaClient()

    if args.command == "get-file":
        result = client.get_file(args.file_key)
    elif args.command == "list-comments":
        result = client.list_comments(args.file_key)
    elif args.command == "export-images":
        result = client.export_images(args.file_key, args.node_ids, args.format)
    elif args.command == "get-file-versions":
        result = client.get_file_versions(args.file_key)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

