#!/usr/bin/env python3
"""Linear CLI for managing issues via the Linear GraphQL API."""
import argparse
import json
import os
import sys
import requests


class LinearClient:
    """Client for Linear GraphQL API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("LINEAR_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "LINEAR_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.api_url = "https://api.linear.app/graphql"
        self.headers = {
            "Authorization": self.api_key,
            "Content-Type": "application/json",
        }

    def _graphql(self, query, variables=None):
        """Execute a GraphQL query against the Linear API."""
        payload = {"query": query}
        if variables:
            payload["variables"] = variables

        try:
            response = requests.post(
                self.api_url,
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            data = response.json()
            if "errors" in data:
                return {"error": data["errors"][0]["message"], "errors": data["errors"]}
            return data.get("data", data)
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_issues(self, team=None):
        """List issues, optionally filtered by team key."""
        filter_clause = ""
        variables = {}
        if team:
            filter_clause = '(filter: { team: { key: { eq: $team } } })'
            variables["team"] = team

        variable_defs = "($team: String)" if team else ""

        query = f"""
        query {variable_defs} {{
            issues{filter_clause} {{
                nodes {{
                    id
                    identifier
                    title
                    state {{ name }}
                    assignee {{ name }}
                    priority
                    createdAt
                    updatedAt
                }}
            }}
        }}
        """
        return self._graphql(query, variables if variables else None)

    def create_issue(self, team, title, description=None):
        """Create a new issue in a team."""
        # First resolve team key to team ID
        team_query = """
        query ($key: String!) {
            teams(filter: { key: { eq: $key } }) {
                nodes { id name key }
            }
        }
        """
        team_result = self._graphql(team_query, {"key": team})
        if "error" in team_result:
            return team_result

        teams = team_result.get("teams", {}).get("nodes", [])
        if not teams:
            return {"error": f"Team with key '{team}' not found"}

        team_id = teams[0]["id"]

        mutation = """
        mutation ($teamId: String!, $title: String!, $description: String) {
            issueCreate(input: { teamId: $teamId, title: $title, description: $description }) {
                success
                issue {
                    id
                    identifier
                    title
                    url
                }
            }
        }
        """
        variables = {"teamId": team_id, "title": title}
        if description:
            variables["description"] = description
        return self._graphql(mutation, variables)

    def update_issue(self, issue_id, state=None, title=None):
        """Update an existing issue."""
        input_fields = {}
        if title:
            input_fields["title"] = title
        if state:
            # Resolve state name to state ID
            state_query = """
            query ($name: String!) {
                workflowStates(filter: { name: { eq: $name } }) {
                    nodes { id name }
                }
            }
            """
            state_result = self._graphql(state_query, {"name": state})
            if "error" in state_result:
                return state_result
            states = state_result.get("workflowStates", {}).get("nodes", [])
            if not states:
                return {"error": f"Workflow state '{state}' not found"}
            input_fields["stateId"] = states[0]["id"]

        if not input_fields:
            return {"error": "At least --state or --title is required for update"}

        # Build dynamic input
        input_json = json.dumps(input_fields)
        mutation = f"""
        mutation {{
            issueUpdate(id: "{issue_id}", input: {input_json}) {{
                success
                issue {{
                    id
                    identifier
                    title
                    state {{ name }}
                }}
            }}
        }}
        """
        return self._graphql(mutation)

    def get_issue(self, issue_id):
        """Get details of a specific issue."""
        query = """
        query ($id: String!) {
            issue(id: $id) {
                id
                identifier
                title
                description
                state { name }
                assignee { name email }
                priority
                labels { nodes { name } }
                createdAt
                updatedAt
                url
            }
        }
        """
        return self._graphql(query, {"id": issue_id})


def main():
    parser = argparse.ArgumentParser(description="Linear CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    list_parser = subparsers.add_parser("list-issues", help="List issues")
    list_parser.add_argument("--team", help="Team key to filter by (e.g., ENG)")

    create_parser = subparsers.add_parser("create-issue", help="Create an issue")
    create_parser.add_argument(
        "--team", required=True, help="Team key (e.g., ENG)"
    )
    create_parser.add_argument("--title", required=True, help="Issue title")
    create_parser.add_argument("--description", help="Issue description (Markdown)")

    update_parser = subparsers.add_parser("update-issue", help="Update an issue")
    update_parser.add_argument("--issue-id", required=True, help="Linear issue ID")
    update_parser.add_argument("--state", help="New workflow state name")
    update_parser.add_argument("--title", help="New title")

    get_parser = subparsers.add_parser("get-issue", help="Get issue details")
    get_parser.add_argument("--issue-id", required=True, help="Linear issue ID")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = LinearClient()

    if args.command == "list-issues":
        result = client.list_issues(team=getattr(args, "team", None))
    elif args.command == "create-issue":
        result = client.create_issue(
            args.team, args.title,
            description=getattr(args, "description", None),
        )
    elif args.command == "update-issue":
        result = client.update_issue(
            args.issue_id,
            state=getattr(args, "state", None),
            title=getattr(args, "title", None),
        )
    elif args.command == "get-issue":
        result = client.get_issue(args.issue_id)

    print(json.dumps(result, indent=2))

    if isinstance(result, dict) and "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Mailgun CLI for sending emails and listing events."""
import argparse
import json
import os
import sys
import requests


class MailgunClient:
    """Client for Mailgun API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("MAILGUN_API_KEY", "")
        self.domain = os.environ.get("MAILGUN_DOMAIN", "")
        if not self.api_key or not self.domain:
            print(
                '{"error": "MAILGUN_API_KEY and MAILGUN_DOMAIN environment variables required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = f"https://api.mailgun.net/v3/{self.domain}"
        self.auth = ("api", self.api_key)

    def send(self, to, from_addr, subject, text=None, html=None):
        """Send an email."""
        if not text and not html:
            return {"error": "Either --text or --html is required"}

        data = {
            "from": from_addr,
            "to": [to],
            "subject": subject,
        }
        if text:
            data["text"] = text
        if html:
            data["html"] = html

        try:
            response = requests.post(
                f"{self.base_url}/messages",
                auth=self.auth,
                data=data,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_events(self, limit=100):
        """List recent email events."""
        try:
            response = requests.get(
                f"{self.base_url}/events",
                auth=self.auth,
                params={"limit": limit},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Mailgun CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    send_parser = subparsers.add_parser("send", help="Send an email")
    send_parser.add_argument("--to", required=True, help="Recipient email address")
    send_parser.add_argument("--from", dest="from_addr", required=True, help="Sender email address")
    send_parser.add_argument("--subject", required=True, help="Email subject")
    send_parser.add_argument("--text", help="Plain text body")
    send_parser.add_argument("--html", help="HTML body")

    events_parser = subparsers.add_parser("list-events", help="List recent events")
    events_parser.add_argument(
        "--limit", type=int, default=100, help="Max events (default: 100)"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = MailgunClient()

    if args.command == "send":
        result = client.send(
            args.to, args.from_addr, args.subject, args.text, args.html
        )
    elif args.command == "list-events":
        result = client.list_events(args.limit)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Microsoft Teams CLI for sending messages and adaptive cards via webhooks."""
import argparse
import json
import os
import sys
import requests


class TeamsClient:
    """Client for Microsoft Teams webhook interactions."""

    def __init__(self):
        self.webhook_url = os.environ.get("TEAMS_WEBHOOK_URL", "")
        if not self.webhook_url:
            print(
                '{"error": "TEAMS_WEBHOOK_URL environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)

    def send(self, text):
        """Send a plain text message to Teams."""
        payload = {"text": text}

        try:
            response = requests.post(
                self.webhook_url,
                json=payload,
                headers={"Content-Type": "application/json"},
                timeout=30,
            )
            response.raise_for_status()
            return {"success": True, "message": "Message sent to Teams"}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def send_card(self, title, text, color="0076D7"):
        """Send an adaptive card message to Teams."""
        payload = {
            "@type": "MessageCard",
            "@context": "http://schema.org/extensions",
            "themeColor": color,
            "summary": title,
            "sections": [
                {
                    "activityTitle": title,
                    "text": text,
                    "markdown": True,
                }
            ],
        }

        try:
            response = requests.post(
                self.webhook_url,
                json=payload,
                headers={"Content-Type": "application/json"},
                timeout=30,
            )
            response.raise_for_status()
            return {"success": True, "message": "Card sent to Teams", "title": title}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Microsoft Teams CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    send_parser = subparsers.add_parser("send", help="Send a text message")
    send_parser.add_argument("--text", required=True, help="Message text")

    card_parser = subparsers.add_parser("send-card", help="Send an adaptive card")
    card_parser.add_argument("--title", required=True, help="Card title")
    card_parser.add_argument("--text", required=True, help="Card body text")
    card_parser.add_argument(
        "--color", default="0076D7", help="Theme color hex (default: 0076D7)"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = TeamsClient()

    if args.command == "send":
        result = client.send(args.text)
    elif args.command == "send-card":
        result = client.send_card(args.title, args.text, args.color)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

