"""Sentry CLI for listing, inspecting, and resolving issues and projects."""
import argparse
import json
import os
import sys
import requests


class SentryClient:
    """Client for Sentry API interactions."""

    def __init__(self):
        self.token = os.environ.get("SENTRY_AUTH_TOKEN", "")
        if not self.token:
