    subparsers.add_parser("get-balance", help="Get Stripe balance")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = StripeClient()

    if args.command == "list-customers":
        result = client.list_customers()
    elif args.command == "get-customer":
